+    #[test]
+    fn disk_pressure_as_u64_roundtrip() {
+        for &(variant, expected) in &[
+            (DiskPressure::Ok, 0u64),
+            (DiskPressure::Warning, 1),
+            (DiskPressure::Critical, 2),
+            (DiskPressure::Fatal, 3),
+        ] {
+            assert_eq!(variant.as_u64(), expected);
